31	  UsersRegisterResult,
32	  UsersRevokeResult,
33	  ViewResult,
34	} from "../types";
35	import { resolveAuthor } from "./auth";
36	import { ErrorCodes, TrackgenticError } from "./errors";
37	import { appendEvent, computeComments, computeState, replayEvents } from "./events";
38	import { atomicWriteJSON, readJSON } from "./file-io";
39	import { generateCommentId, generateId } from "./id";
40	import {
41	  addChild,
42	  findEntry,
43	  getChildren,
44	  insertEntry,
45	  readIndex,
46	  removeChild,
47	  updateEntry,
48	  writeIndex,
49	} from "./index-manager";
50	import { resolveTrackerDir } from "./resolution";
51	import {
52	  computeUpwardPromotions,
53	  isStatusAfter,
54	  validateNewChild,
55	  validateParentStatusChange,
56	} from "./hierarchy";
57	
58	const TRACKGENTIC_DIR = ".trackgentic";
59	
60	/**
61	 * Default config.json contents.
62	 */
63	const DEFAULT_CONFIG: ConfigFile = {
64	  auth: {
65	    mode: "open",
66	    defaultUser: "anonymous",
67	  },
68	};
69	
70	/**
71	 * Default index.json contents.
72	 */
73	const DEFAULT_INDEX: IndexFile = {
74	  open: [],
75	  closed: [],
76	  childrenOf: {},
77	};
78	
79	/**
80	 * Default dependencies.json contents.
81	 */
82	const DEFAULT_DEPENDENCIES: DependenciesFile = {
83	  blockedBy: {},
84	  blocks: {},
85	};
86	
87	/**
88	 * Default users.json contents.
89	 */
90	const DEFAULT_USERS: UsersFile = {
91	  users: [],
92	};
93	
94	/**
95	 * Generate a token: tk_ + 8 random alphanumeric characters.
96	 */
97	function generateToken(): string {
98	  return `tk_${Math.random().toString(36).slice(2, 10)}`;
99	}
100	
101	/**
102	 * Recursively auto-close done children when a parent is closed.
103	 * Appends system-authored events to each child's issue file and updates the index.
104	 * Returns the updated index.
105	 */
106	async function cascadeClose(
107	  index: IndexFile,
108	  issueId: IssueId,
109	  trackerDir: string,
110	): Promise<IndexFile> {
111	  const childIds = getChildren(index, issueId);
112	  let currentIndex = index;
113	
114	  for (const childId of childIds) {
115	    const childEntry = findEntry(currentIndex, childId);
116	    if (!childEntry || childEntry.status !== "done") continue;
117	
118	    const now = new Date().toISOString();
119	    const event: Event = {
120	      type: "update",
121	      timestamp: now,
122	      author: "system",
123	      content: {
124	        status: "closed",
125	        reason: "auto-closed: parent closed",
126	      },
127	    };
128	
129	    const childPath = join(trackerDir, childEntry.path);
130	    await appendEvent(childPath, event);
131	
132	    currentIndex = updateEntry(currentIndex, childId, { status: "closed" });
133	
134	    // Recursively cascade to the child's own children
135	    currentIndex = await cascadeClose(currentIndex, childId, trackerDir);
136	  }
137	
138	  return currentIndex;
139	}
140	
141	/**
142	 * Tracker — the main programmatic API for trackgentic.
143	 *
144	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
145	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
146	 */
147	export class Tracker {
148	  private cwd: string;
149	
150	  constructor(cwd?: string) {
151	    this.cwd = cwd ?? process.cwd();
152	  }
153	
154	  /**
155	   * Initialize a new `.trackgentic/` directory in `cwd`.
156	   */
157	  async init(): Promise<InitResult> {
158	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
159	
160	    if (existsSync(trackerDir)) {
161	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
162	    }
163	
164	    mkdirSync(trackerDir, { recursive: true });
165	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
166	
167	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
168	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
169	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
170	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
171	
172	    return { result: "OK", path: resolve(trackerDir) };
173	  }
174	
175	  /**
176	   * Create a new issue.
177	   */
178	  async create(params: CreateParams): Promise<CreateResult> {
179	    const trackerDir = resolveTrackerDir(this.cwd);
180	    if (!trackerDir) {
181	      throw new TrackgenticError(
182	        ErrorCodes.NOT_INITIALIZED.result,
183	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
184	        ErrorCodes.NOT_INITIALIZED.exitCode,
185	      );
186	    }
187	
188	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
189	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
190	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
191	    if (authResult instanceof TrackgenticError) return authResult;
192	    const author = params.author ?? authResult.author;
193	
194	    const id = generateId();
195	    const issuePath = params.path ?? `issues/${id}.json`;
196	    const now = new Date().toISOString();
197	
198	    const title = params.title;
199	    const description = params.description ?? "";
200	    const status: IssueStatus = params.status ?? "idea";
201	    const priority = params.priority ?? 3;
202	    const assignee = params.assignee ?? null;
203	    const parentId = params.parentId ?? null;
204	    const tags = params.tags ?? [];
205	
206	    // Read index early for parent validation
207	    const index = await readIndex(trackerDir);
208	
209	    // Validate parent exists and is not closed
210	    if (parentId) {
211	      const parentEntry = findEntry(index, parentId);
212	      if (!parentEntry) {
213	        throw new TrackgenticError(
214	          ErrorCodes.NOT_FOUND.result,
215	          "Parent issue not found",
216	          ErrorCodes.NOT_FOUND.exitCode,
217	        );
218	      }
219	      const validationError = validateNewChild(parentEntry);
220	      if (validationError) {
221	        throw new TrackgenticError(
222	          ErrorCodes.HIERARCHY_CONSTRAINT.result,
223	          validationError,
224	          ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
225	        );
226	      }
227	    }
228	
229	    // Build update content with only non-default values
230	    const updateContent: Partial<
231	      Pick<
232	        IssueProperties,
233	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
234	      >
235	    > & { title: string } = { title };
236	    if (description) updateContent.description = description;
237	    if (status !== "idea") updateContent.status = status;
238	    if (priority !== 3) updateContent.priority = priority;
239	    if (assignee !== null) updateContent.assignee = assignee;
240	    if (parentId !== null) updateContent.parentId = parentId;
241	    if (tags.length > 0) updateContent.tags = tags;
242	
243	    // Create issue file with two events: creation + update
244	    const creationEvent = { type: "creation" as const, timestamp: now, author };
245	    const updateEvent = {
246	      type: "update" as const,
247	      timestamp: now,
248	      author,
249	      content: updateContent,
250	    };
251	
252	    const issueFilePath = join(trackerDir, issuePath);
253	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
254	
255	    // Build index entry and insert into index
256	    const entry: IndexEntry = {
257	      id,
258	      title,
259	      path: issuePath,
260	      status,
261	      assignee,
262	      parentId,
263	      tags,
264	      priority,
265	    };
266	
267	    const updatedIndex = insertEntry(index, entry);
268	    await writeIndex(trackerDir, updatedIndex);
269	
270	    return { id };
271	  }
272	
273	  /**
274	   * List issues from the index, with optional filters.
275	   */
276	  async list(params?: ListParams): Promise<ListResult> {
277	    const trackerDir = resolveTrackerDir(this.cwd);
278	    if (!trackerDir) {
279	      throw new TrackgenticError(
280	        ErrorCodes.NOT_INITIALIZED.result,
281	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
282	        ErrorCodes.NOT_INITIALIZED.exitCode,
283	      );
284	    }
285	
286	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
287	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
288	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
289	    if (authResult instanceof TrackgenticError) {
290	      throw authResult;
291	    }
292	
293	    const index = await readIndex(trackerDir);
294	
295	    // Determine source arrays based on params.status
296	    let entries: IndexEntry[];
297	    if (params?.status === "closed") {
298	      entries = index.closed;
299	    } else if (params?.status === "open") {
300	      entries = index.open;
301	    } else if (params?.status) {
302	      entries = index.open;
303	    } else {
304	      entries = [...index.open, ...index.closed];
305	    }
306	
307	    // Filter in memory
308	    let filtered = entries;
309	
310	    if (params?.status && params.status !== "open" && params.status !== "closed") {
311	      filtered = filtered.filter((e) => e.status === params.status);
312	    }
313	
314	    if (params?.assignee) {
315	      filtered = filtered.filter((e) => e.assignee === params.assignee);
316	    }
317	
318	    if (params?.tags && params.tags.length > 0) {
319	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
320	    }
321	
322	    if (params?.parentId !== undefined) {
323	      if (params.parentId === null) {
324	        filtered = filtered.filter((e) => e.parentId === null);
325	      } else {
326	        filtered = filtered.filter((e) => e.parentId === params.parentId);
327	      }
328	    }
329	
330	    // Sort: priority ASC → id ASC
331	    filtered.sort((a, b) => {
332	      if (a.priority !== b.priority) return a.priority - b.priority;
333	      return a.id.localeCompare(b.id);
334	    });
335	
336	    return filtered;
337	  }
338	
339	  /**
340	   * View a single issue's full computed state.
341	   */
342	  async view(id: IssueId): Promise<ViewResult> {
343	    const trackerDir = resolveTrackerDir(this.cwd);
344	    if (!trackerDir) {
345	      throw new TrackgenticError(
346	        ErrorCodes.NOT_INITIALIZED.result,
347	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
348	        ErrorCodes.NOT_INITIALIZED.exitCode,
349	      );
350	    }
351	
352	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
353	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
354	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
355	    if (authResult instanceof TrackgenticError) {
356	      throw authResult;
357	    }
358	
359	    const index = await readIndex(trackerDir);
360	    const entry = findEntry(index, id);
361	    if (!entry) {
362	      throw new TrackgenticError(
363	        ErrorCodes.NOT_FOUND.result,
364	        `Issue ${id} not found in index.`,
365	        ErrorCodes.NOT_FOUND.exitCode,
366	      );
367	    }
368	
369	    const issueFilePath = join(trackerDir, entry.path);
370	    if (!existsSync(issueFilePath)) {
371	      throw new TrackgenticError(
372	        ErrorCodes.ISSUE_MISSING.result,
373	        `Issue file for ${id} is missing.`,
374	        ErrorCodes.ISSUE_MISSING.exitCode,
375	      );
376	    }
377	
378	    const events = await replayEvents(issueFilePath);
379	    return computeState(events, id);
380	  }
381	
382	  /**
383	   * Update an existing issue.
384	   */
385	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
386	    const trackerDir = resolveTrackerDir(this.cwd);
387	    if (!trackerDir) {
388	      throw new TrackgenticError(
389	        ErrorCodes.NOT_INITIALIZED.result,
390	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
391	        ErrorCodes.NOT_INITIALIZED.exitCode,
392	      );
393	    }
394	
395	    // Validate at least one field provided (besides author)
396	    const hasField =
397	      params.title !== undefined ||
398	      params.description !== undefined ||
399	      params.status !== undefined ||
400	      params.assignee !== undefined ||
401	      params.tags !== undefined ||
402	      params.priority !== undefined ||
403	      params.parentId !== undefined;
404	
405	    if (!hasField) {
406	      throw new TrackgenticError(
407	        ErrorCodes.INVALID_PARAMS.result,
408	        "At least one field must be provided for update.",
409	        ErrorCodes.INVALID_PARAMS.exitCode,
410	      );
411	    }
412	
413	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
414	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
415	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
416	    if (authResult instanceof TrackgenticError) return authResult;
417	    const author = params.author ?? authResult.author;
418	
419	    const index = await readIndex(trackerDir);
420	    const entry = findEntry(index, id);
421	    if (!entry) {
422	      throw new TrackgenticError(
423	        ErrorCodes.NOT_FOUND.result,
424	        `Issue ${id} not found in index.`,
425	        ErrorCodes.NOT_FOUND.exitCode,
426	      );
427	    }
428	
429	    const issueFilePath = join(trackerDir, entry.path);
430	    if (!existsSync(issueFilePath)) {
431	      throw new TrackgenticError(
432	        ErrorCodes.ISSUE_MISSING.result,
433	        `Issue file for ${id} is missing.`,
434	        ErrorCodes.ISSUE_MISSING.exitCode,
435	      );
436	    }
437	
438	    // Save old values for hierarchy handling
439	    const oldStatus = entry.status;
440	    const oldParentId = entry.parentId;
441	
442	    // ── Hierarchy validation (before any state changes) ────────────
443	
444	    // Validate downward constraints for status change
445	    if (params.status !== undefined && params.status !== oldStatus) {
446	      if (params.status === "done" || params.status === "closed") {
447	        const childIds = getChildren(index, id);
448	        const childEntries = childIds
449	          .map((cid) => findEntry(index, cid))
450	          .filter((e): e is IndexEntry => e !== null);
451	        const validationError = validateParentStatusChange(index, childEntries, params.status);
452	        if (validationError) {
453	          throw new TrackgenticError(
454	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
455	            validationError,
456	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
457	          );
458	        }
459	      }
460	    }
461	
462	    // Validate reparenting constraints
463	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
464	      if (params.parentId !== null) {
465	        const newParentEntry = findEntry(index, params.parentId);
466	        if (!newParentEntry) {
467	          throw new TrackgenticError(
468	            ErrorCodes.NOT_FOUND.result,
469	            "Parent issue not found",
470	            ErrorCodes.NOT_FOUND.exitCode,
471	          );
472	        }
473	        const validationError = validateNewChild(newParentEntry);
474	        if (validationError) {
475	          throw new TrackgenticError(
476	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
477	            validationError,
478	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
479	          );
480	        }
481	      }
482	    }
483	
484	    // ── Build and append update event ──────────────────────────────
485	
486	    // Build update event content with only the provided fields
487	    const content: Partial<
488	      Pick<
489	        IssueProperties,
490	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
491	      >
492	    > = {};
493	    if (params.title !== undefined) content.title = params.title;
494	    if (params.description !== undefined) content.description = params.description;
495	    if (params.status !== undefined) content.status = params.status;
496	    if (params.assignee !== undefined) content.assignee = params.assignee;
497	    if (params.tags !== undefined) content.tags = params.tags;
498	    if (params.priority !== undefined) content.priority = params.priority;
499	    if (params.parentId !== undefined) content.parentId = params.parentId;
500	
501	    const now = new Date().toISOString();
502	
503	    const updateEvent = {
504	      type: "update" as const,
505	      timestamp: now,
506	      author,
507	      content,
508	    };
509	
510	    // Append event to issue file
511	    await appendEvent(issueFilePath, updateEvent);
512	
513	    // Recompute state from all events
514	    const events = await replayEvents(issueFilePath);
515	    const computed = computeState(events, id);
516	
517	    // Update index entry with new computed values
518	    let updatedIndex = updateEntry(index, id, {
519	      title: computed.title,
520	      status: computed.status,
521	      assignee: computed.assignee,
522	      parentId: computed.parentId,
523	      tags: computed.tags,
524	      priority: computed.priority,
525	    });
526	
527	    // ── Hierarchy handling (after event append, before index write) ─
528	
529	    // 1. Handle reparenting (childrenOf updates)
530	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
531	      // Detach from old parent
532	      if (oldParentId !== null) {
533	        updatedIndex = removeChild(updatedIndex, oldParentId, id);
534	      }
535	      // Attach to new parent
536	      if (params.parentId !== null) {
537	        updatedIndex = addChild(updatedIndex, params.parentId, id);
538	
539	        // Upward promotion for reparenting: if child's status is past new parent's status
540	        const newParentEntry = findEntry(updatedIndex, params.parentId);
541	        if (newParentEntry && isStatusAfter(computed.status, newParentEntry.status)) {
542	          const promotions = computeUpwardPromotions(
543	            updatedIndex,
544	            newParentEntry,
545	            computed.status,
546	            (iid) => findEntry(updatedIndex, iid),
547	          );
548	          for (const promo of promotions) {
549	            const promoEntry = findEntry(updatedIndex, promo.issueId);
550	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
551	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
552	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
553	                status: promo.event.content.status,
554	              });
555	            }
556	          }
557	        }
558	      }
559	    }
560	
561	    // 2. Handle status change
562	    if (params.status !== undefined && params.status !== oldStatus) {
563	      // Downward cascade: auto-close done children when parent closes
564	      if (params.status === "closed") {
565	        updatedIndex = await cascadeClose(updatedIndex, id, trackerDir);
566	      }
567	
568	      // Upward promotion: promote parent if child advanced past it
569	      const currentParentId = computed.parentId;
570	      if (currentParentId) {
571	        const parentEntry = findEntry(updatedIndex, currentParentId);
572	        if (parentEntry && isStatusAfter(params.status, parentEntry.status)) {
573	          const promotions = computeUpwardPromotions(
574	            updatedIndex,
575	            parentEntry,
576	            params.status,
577	            (iid) => findEntry(updatedIndex, iid),
578	          );
579	          for (const promo of promotions) {
580	            const promoEntry = findEntry(updatedIndex, promo.issueId);
581	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
582	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
583	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
584	                status: promo.event.content.status,
585	              });
586	            }
587	          }
588	        }
589	      }
590	    }
591	
592	    await writeIndex(trackerDir, updatedIndex);
593	
594	    return { result: "OK" };
595	  }
