141	/**
142	 * Add childId to parentId's children array in childrenOf map.
143	 * If the key doesn't exist, creates it. Ignores duplicates.
144	 * Returns a new IndexFile (immutable — original is not mutated).
145	 */
146	export function addChild(index: IndexFile, parentId: IssueId, childId: IssueId): IndexFile {
147	  const existing = index.childrenOf[parentId];
148	  if (existing && existing.includes(childId)) {
149	    return index; // Already present — no change
150	  }
151	  const childrenOf = { ...index.childrenOf };
152	  childrenOf[parentId] = existing ? [...existing, childId] : [childId];
153	  return { ...index, childrenOf };
154	}
155	
156	/**
157	 * Remove childId from parentId's children array in childrenOf map.
158	 * Deletes the key from the map if the resulting array is empty.
159	 * Returns a new IndexFile (immutable — original is not mutated).
160	 */
161	export function removeChild(index: IndexFile, parentId: IssueId, childId: IssueId): IndexFile {
162	  const existing = index.childrenOf[parentId];
163	  if (!existing) return index;
164	  const filtered = existing.filter((id) => id !== childId);
165	  if (filtered.length === existing.length) return index; // Not found — no change
166	  const childrenOf = { ...index.childrenOf };
167	  if (filtered.length === 0) {
168	    delete childrenOf[parentId];
169	  } else {
170	    childrenOf[parentId] = filtered;
171	  }
172	  return { ...index, childrenOf };
173	}
174	
175	/**
176	 * Get all child IDs for a given parent. Returns empty array if no children.
177	 */
178	export function getChildren(index: IndexFile, parentId: IssueId): IssueId[] {
179	  return index.childrenOf[parentId] ?? [];
180	}
181	
182	/**
183	 * Remove entry from whichever array it's in.
184	 * Returns unchanged index if not found.
185	 * Returns a new IndexFile (immutable — original is not mutated).
186	 */
187	export function removeEntry(index: IndexFile, id: IssueId): IndexFile {
188	  const openIdx = binarySearchIndex(index.open, id);
189	  if (openIdx !== -1) {
190	    return { ...index, open: [...index.open.slice(0, openIdx), ...index.open.slice(openIdx + 1)] };
191	  }
192	
193	  const closedIdx = binarySearchIndex(index.closed, id);
194	  if (closedIdx !== -1) {
195	    return {
196	      ...index,
197	      closed: [...index.closed.slice(0, closedIdx), ...index.closed.slice(closedIdx + 1)],
198	    };
199	  }
200	
201	  return index;
202	}
